type Listener = (...args: unknown[]) => void;

export class EventEmitter {
  private _listeners: Map<string, Listener[]> = new Map();

  // Register listener, return unsubscribe function
  on(event: string, listener: Listener): () => void {
    if (!this._listeners.has(event)) {
      this._listeners.set(event, []);
    }
    this._listeners.get(event)!.push(listener);
    return () => this.off(event, listener);
  }

  // Listener fires only once
  once(event: string, listener: Listener): void {
    const wrapper: Listener = (...args: unknown[]) => {
      this.off(event, wrapper);
      listener(...args);
    };
    this.on(event, wrapper);
  }

  // Call all listeners, return true if any existed
  emit(event: string, ...args: unknown[]): boolean {
    const listeners = this._listeners.get(event);
    if (!listeners || listeners.length === 0) {
      return false;
    }
    // Snapshot before iterating so self-removal during emit doesn't crash
    const snapshot = [...listeners];
    for (const listener of snapshot) {
      listener(...args);
    }
    return true;
  }

  // Remove a specific listener
  off(event: string, listener: Listener): void {
    const listeners = this._listeners.get(event);
    if (!listeners) return;
    const index = listeners.indexOf(listener);
    if (index !== -1) {
      listeners.splice(index, 1);
    }
    if (listeners.length === 0) {
      this._listeners.delete(event);
    }
  }

  // Remove all listeners, or all for a specific event
  removeAllListeners(event?: string): void {
    if (event === undefined) {
      this._listeners.clear();
    } else {
      this._listeners.delete(event);
    }
  }

  // Return count of listeners for an event
  listenerCount(event: string): number {
    return this._listeners.get(event)?.length ?? 0;
  }

  // Return array of event names that have listeners
  eventNames(): string[] {
    return [...this._listeners.keys()];
  }
}

